void quicksort(std::vector<int>& a, int l, int h) {
    while (l < h) {
        if (h - l < 15) {
            for (int i = l + 1; i <= h; ++i) {
                int k = a[i], j = i - 1;
                for (; j >= l && a[j] > k; --j) a[j + 1] = a[j];
                a[j + 1] = k;
            }
            return;
        }
        int i = l - 1, j = h + 1, p = a[l + (h - l) / 2];
        while (1) {
            while (a[++i] < p);
            while (a[--j] > p);
            if (i >= j) break;
            std::swap(a[i], a[j]);
        }
        if (j - l < h - j) { quicksort(a, l, j); l = j + 1; }
        else { quicksort(a, j + 1, h); h = j; }
    }
}

